// app/(creator)/subscribers/page.tsx
"use client"

import { useState } from "react"
import { Button } from "@/components/ui/Button"
import { Avatar, SectionLabel, SidebarItem, Tag } from "@/components/ui/hubora-ui"
import { cn } from "@/lib/utils"

type PlanFilter = "all" | "Basic" | "Pro" | "VIP"

const SUBSCRIBERS = [
  { id: "1",  name: "Kemi Adeyemi",  handle: "@kemiadeyemi",  plan: "Pro",   gradient: "violet" as const, joined: "Mar 1, 2026",  spent: "₦7,500",  status: "active" },
  { id: "2",  name: "Tunde Williams", handle: "@tundewill",   plan: "VIP",   gradient: "teal"   as const, joined: "Feb 20, 2026", spent: "₦15,000", status: "active" },
  { id: "3",  name: "Sola Okafor",   handle: "@solaokafor",   plan: "Basic", gradient: "amber"  as const, joined: "Feb 14, 2026", spent: "₦2,000",  status: "active" },
  { id: "4",  name: "Ada Nwosu",     handle: "@adanwosu",     plan: "Pro",   gradient: "rose"   as const, joined: "Feb 10, 2026", spent: "₦5,000",  status: "active" },
  { id: "5",  name: "Emeka Eze",     handle: "@emekaeze",     plan: "Basic", gradient: "blue"   as const, joined: "Jan 30, 2026", spent: "₦3,000",  status: "active" },
  { id: "6",  name: "Ngozi Obi",     handle: "@ngoziobi",     plan: "VIP",   gradient: "violet" as const, joined: "Jan 22, 2026", spent: "₦25,000", status: "active" },
  { id: "7",  name: "Chioma Ibe",    handle: "@chiomaibe",    plan: "Pro",   gradient: "teal"   as const, joined: "Jan 15, 2026", spent: "₦10,000", status: "active" },
  { id: "8",  name: "Bola Savage",   handle: "@bolasavage",   plan: "Basic", gradient: "amber"  as const, joined: "Jan 8, 2026",  spent: "₦1,000",  status: "cancelled" },
  { id: "9",  name: "Femi Coker",    handle: "@femicoker",    plan: "Pro",   gradient: "rose"   as const, joined: "Dec 20, 2025", spent: "₦7,500",  status: "active" },
  { id: "10", name: "Zara Ahmed",    handle: "@zaraahmed",    plan: "VIP",   gradient: "blue"   as const, joined: "Dec 10, 2025", spent: "₦20,000", status: "active" },
]

export default function CreatorSubscribersPage() {
  const [planFilter, setPlanFilter] = useState<PlanFilter>("all")
  const [search, setSearch] = useState("")

  const filtered = SUBSCRIBERS
    .filter(s => planFilter === "all" || s.plan === planFilter)
    .filter(s => s.name.toLowerCase().includes(search.toLowerCase()) || s.handle.includes(search))

  const total = SUBSCRIBERS.length
  const active = SUBSCRIBERS.filter(s => s.status === "active").length

  return (
    <div className="flex min-h-screen bg-[#FAFAFA]">

      <main className="flex-1 px-8 py-8">

        {/* Header */}
        <div className="flex items-start justify-between mb-8">
          <div>
            <h1 className="font-display text-[24px] font-bold text-[#0F0F14] tracking-tight">Subscribers</h1>
            <p className="font-body text-[13px] text-[#9CA3AF] mt-1">{active} active · {total - active} cancelled</p>
          </div>
          <Button variant="outline" size="md">Export CSV</Button>
        </div>

        {/* Plan breakdown pills */}
        <div className="grid grid-cols-4 gap-4 mb-8">
          {[
            { label: "All", value: total,  sub: "total subscribers",    color: "bg-[#F9FAFB]",  border: "border-[#E5E7EB]", text: "text-[#0F0F14]", active: planFilter === "all" },
            { label: "Basic", value: SUBSCRIBERS.filter(s=>s.plan==="Basic").length, sub: "subscribers", color: "bg-[#ECFDF5]", border: "border-[#A7F3D0]", text: "text-[#059669]", active: planFilter === "Basic" },
            { label: "Pro",   value: SUBSCRIBERS.filter(s=>s.plan==="Pro").length,   sub: "subscribers", color: "bg-[#F5F3FF]", border: "border-[#DDD6FE]", text: "text-[#6C36F5]", active: planFilter === "Pro" },
            { label: "VIP",   value: SUBSCRIBERS.filter(s=>s.plan==="VIP").length,   sub: "subscribers", color: "bg-[#FFFBEB]", border: "border-[#FDE68A]", text: "text-[#D97706]", active: planFilter === "VIP" },
          ].map(card => (
            <button
              key={card.label}
              onClick={() => setPlanFilter(card.label as PlanFilter)}
              className={cn(
                "text-left p-4 rounded-2xl border-[1.5px] transition-all duration-150",
                card.active
                  ? `${card.color} ${card.border} shadow-[0_2px_8px_-1px_rgba(0,0,0,0.07)]`
                  : "bg-white border-[#E5E7EB] hover:border-[#D1D5DB]"
              )}
            >
              <p className={cn("font-display font-bold text-[26px] leading-none", card.active ? card.text : "text-[#0F0F14]")}>{card.value}</p>
              <p className="font-body text-[12px] text-[#9CA3AF] mt-1">{card.label} {card.sub}</p>
            </button>
          ))}
        </div>

        {/* Search */}
        <div className="mb-4">
          <input
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search subscribers…"
            className="w-full max-w-[320px] bg-white border-[1.5px] border-[#E5E7EB] rounded-xl px-4 py-2.5 text-[13px] font-body outline-none focus:border-[#6C36F5] focus:shadow-[0_0_0_3px_rgba(108,54,245,0.1)] transition-all shadow-[0_1px_2px_0_rgba(0,0,0,0.04)]"
          />
        </div>

        {/* Table */}
        <div className="bg-white rounded-2xl overflow-hidden shadow-[0_0_0_1px_rgba(0,0,0,0.04),0_2px_8px_-2px_rgba(0,0,0,0.06)]">
          <div className="grid grid-cols-[1fr_90px_100px_100px_90px_60px] gap-4 px-5 py-3.5 bg-[#FAFAFA] border-b border-[#F3F4F6]">
            {["Subscriber", "Plan", "Joined", "Total Spent", "Status", ""].map(h => (
              <span key={h} className="font-body text-[11px] font-semibold uppercase tracking-wider text-[#9CA3AF]">{h}</span>
            ))}
          </div>

          {filtered.length === 0 ? (
            <div className="py-16 flex flex-col items-center gap-2">
              <p className="font-display font-semibold text-[15px] text-[#0F0F14]">No subscribers found</p>
              <p className="font-body text-[13px] text-[#9CA3AF]">Try adjusting your search or filter</p>
            </div>
          ) : filtered.map(sub => (
            <div
              key={sub.id}
              className="grid grid-cols-[1fr_90px_100px_100px_90px_60px] gap-4 items-center px-5 py-4 border-b border-[#F9FAFB] last:border-0 hover:bg-[#FAFAFA] transition-colors"
            >
              <div className="flex items-center gap-3">
                <Avatar fallback={sub.name[0]} size="sm" gradient={sub.gradient} ring />
                <div>
                  <p className="font-display font-semibold text-[13px] text-[#0F0F14]">{sub.name}</p>
                  <p className="font-body text-[11px] text-[#9CA3AF]">{sub.handle}</p>
                </div>
              </div>
              <Tag variant={sub.plan === "VIP" ? "amber" : sub.plan === "Pro" ? "violet" : "success"} size="sm" dot>{sub.plan}</Tag>
              <span className="font-body text-[12px] text-[#6B7280]">{sub.joined}</span>
              <span className="font-mono text-[12px] font-semibold text-[#0F0F14]">{sub.spent}</span>
              <span className={sub.status === "active" ? "status-published" : "status-draft"}>{sub.status}</span>
              <Button variant="ghost" size="xs">Message</Button>
            </div>
          ))}
        </div>

      </main>
    </div>
  )
}
